from sentence_transformers import SentenceTransformer, util

class HomieRetriever:
    def __init__(self, docs, backend="pytorch"):
        kwargs = {}
        if backend == "onnx":
            kwargs = {"backend": "onnx",
                      "model_kwargs": {"provider": "CPUExecutionProvider"}}
        self.model = SentenceTransformer("all-MiniLM-L6-v2", **kwargs)
        self.docs = docs
        self.index = self.model.encode(docs, normalize_embeddings=True)

    def query(self, text, top_k=3, threshold=0.3):
        q = self.model.encode(text, normalize_embeddings=True)
        scores = util.cos_sim(q, self.index)[0].tolist()
        ranked = sorted(range(len(scores)), key=lambda i: scores[i], reverse=True)
        return [
            {"text": self.docs[i], "score": scores[i]}
            for i in ranked[:top_k] if scores[i] >= threshold
        ]

    def build_prompt(self, user_msg, top_k=3):
        hits = self.query(user_msg, top_k)
        ctx = "\n".join(f"- {h['text']}" for h in hits)
        return f"Context:\n{ctx}\n\nQuestion: {user_msg}\nAnswer:"

